module adder_pipe_64bit #(
    parameter DATA_WIDTH = 64,
    parameter STG_WIDTH = 16
) (
    input clk,
    input rst_n,
    input i_en,
    input [DATA_WIDTH-1:0] adda,
    input [DATA_WIDTH-1:0] addb,
    output [DATA_WIDTH:0] result,
    output reg o_en
);

    reg [DATA_WIDTH-1:0] adda_reg, addb_reg;
    reg [DATA_WIDTH:0] sum_reg;
    reg [STG_WIDTH-1:0] stage_en_reg;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            adda_reg <= 0;
            addb_reg <= 0;
            sum_reg <= 0;
            stage_en_reg <= 0;
            o_en <= 0;
        end else begin
            adda_reg <= adda;
            addb_reg <= addb;
            sum_reg <= adda_reg + addb_reg;
            stage_en_reg <= {stage_en_reg[STG_WIDTH-2:0], i_en};
            o_en <= stage_en_reg[STG_WIDTH-1];
        end
    end

    assign result = sum_reg;

endmodule
